// 三载体一致:纯 JS、无 DOM/uplink/shadow 足迹
import * as Formula from 'https://cdn.jsdelivr.net/npm/@formulajs/formulajs@4/+esm';
const allowed = new Set(['PMT','PV','FV','NPER','NPV','IRR']);
if (!allowed.has(data.call)) throw new Error('Unsupported Formula.js function');
const result = Formula[data.call](...data.args);
if (result instanceof Error) throw result;
